// Generated by forge proof from worktree-aware-watch.md
import { describe, test, expect, beforeEach } from 'bun:test';
import {
  getTestDb,
  insertWorktree,
  getWorktree,
  querySessionsByWorktree,
  insertSession,
  insertTask,
} from './db.js';
import type { Database } from 'bun:sqlite';

let db: Database;

beforeEach(() => {
  db = getTestDb();
});

function makeWorktreeId(): string {
  return `wt-${Date.now()}-${Math.random().toString(16).substring(2, 6)}`;
}

function insertTestWorktree(overrides: Partial<Parameters<typeof insertWorktree>[1]> = {}): string {
  const id = overrides.id ?? makeWorktreeId();
  insertWorktree(db, {
    id,
    spec_path: 'specs/feature.md',
    branch: 'forge/feature',
    worktree_path: '/tmp/project-watch-test',
    status: 'created',
    ...overrides,
  });
  return id;
}

// ── Session-to-worktree association for watch ────────────────

describe('session discovery via direct session_id link', () => {
  test('finds primary session linked directly to worktree', () => {
    insertSession(db, { id: 'sess-primary', startedAt: '2026-01-01T00:00:00Z' });
    const wtId = insertTestWorktree({ session_id: 'sess-primary' });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toHaveLength(1);
    expect(sessions[0].id).toBe('sess-primary');
  });

  test('returns empty when worktree has no sessions', () => {
    const wtId = insertTestWorktree();
    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toEqual([]);
  });
});

describe('session discovery via task cwd join', () => {
  test('finds sessions associated by task cwd matching worktree path', () => {
    const wtPath = '/tmp/watch-cwd-join';
    const wtId = insertTestWorktree({ worktree_path: wtPath });

    insertSession(db, { id: 'sess-via-task', startedAt: '2026-01-01T00:00:00Z' });
    insertTask(db, {
      id: 'task-watch-1',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-via-task',
    });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toHaveLength(1);
    expect(sessions[0].id).toBe('sess-via-task');
  });

  test('does not find sessions for tasks in different directories', () => {
    const wtId = insertTestWorktree({ worktree_path: '/tmp/wt-A' });

    insertSession(db, { id: 'sess-other', startedAt: '2026-01-01T00:00:00Z' });
    insertTask(db, {
      id: 'task-other-dir',
      command: 'run',
      status: 'completed',
      cwd: '/tmp/completely-different',
      sessionId: 'sess-other',
    });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toEqual([]);
  });
});

describe('session deduplication and ordering', () => {
  test('deduplicates sessions found via both direct and task paths', () => {
    const wtPath = '/tmp/dedup-watch';
    insertSession(db, { id: 'sess-dup', startedAt: '2026-01-01T00:00:00Z' });
    const wtId = insertTestWorktree({
      worktree_path: wtPath,
      session_id: 'sess-dup',
    });

    insertTask(db, {
      id: 'task-dup',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-dup',
    });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toHaveLength(1);
    expect(sessions[0].id).toBe('sess-dup');
  });

  test('sessions ordered by startedAt ASC for chronological following', () => {
    const wtPath = '/tmp/order-watch';
    const wtId = insertTestWorktree({
      worktree_path: wtPath,
      session_id: 'sess-B',
    });

    insertSession(db, { id: 'sess-B', startedAt: '2026-01-02T00:00:00Z' });
    insertSession(db, { id: 'sess-A', startedAt: '2026-01-01T00:00:00Z' });
    insertTask(db, {
      id: 'task-order-watch',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-A',
    });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toHaveLength(2);
    expect(sessions[0].id).toBe('sess-A');
    expect(sessions[1].id).toBe('sess-B');
  });

  test('multiple sessions from different tasks in same worktree', () => {
    const wtPath = '/tmp/multi-session-watch';
    const wtId = insertTestWorktree({ worktree_path: wtPath });

    insertSession(db, { id: 'sess-1', startedAt: '2026-01-01T00:00:00Z' });
    insertSession(db, { id: 'sess-2', startedAt: '2026-01-01T01:00:00Z' });
    insertSession(db, { id: 'sess-3', startedAt: '2026-01-01T02:00:00Z' });

    insertTask(db, {
      id: 'task-m1',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-1',
    });
    insertTask(db, {
      id: 'task-m2',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-2',
    });
    insertTask(db, {
      id: 'task-m3',
      command: 'run',
      status: 'completed',
      cwd: wtPath,
      sessionId: 'sess-3',
    });

    const sessions = querySessionsByWorktree(db, wtId);
    expect(sessions).toHaveLength(3);
    expect(sessions[0].id).toBe('sess-1');
    expect(sessions[2].id).toBe('sess-3');
  });
});

// ── Worktree resolution for watch ────────────────────────────

describe('worktree resolution for watch scoping', () => {
  test('getWorktree returns worktree info for watch context', () => {
    const id = insertTestWorktree({
      branch: 'forge/watch-test-branch',
      worktree_path: '/home/dev/project-watch-wt',
    });

    const wt = getWorktree(db, id);
    expect(wt).not.toBeNull();
    expect(wt!.branch).toBe('forge/watch-test-branch');
  });

  test('getWorktree returns null for invalid worktree ID (watch error path)', () => {
    const wt = getWorktree(db, 'nonexistent-for-watch');
    expect(wt).toBeNull();
  });
});
